var CONSUMET_BASE = "https://api.consumet.org";
class Provider {
  constructor() {
    this.base = CONSUMET_BASE;
  }
  getSettings() {
    return {
      episodeServers: ["Gogocdn SUB", "Vidstreaming SUB"],
      supportsDub: false,
    };
  }
  async search(query) {
    var url = this.base + "/anime/gogoanime/" + encodeURIComponent(query.query);
    var res = await fetch(url);
    var data = await res.json();
    if (!data || !data.results || !data.results.length) throw new Error("No results");
    var results = [];
    for (var i = 0; i < data.results.length; i++) {
      var item = data.results[i];
      results.push({ id: item.id, title: item.title, url: item.url || "", subOrDub: "sub" });
    }
    return results;
  }
  async findEpisodes(id) {
    var url = this.base + "/anime/gogoanime/info/" + encodeURIComponent(id);
    var res = await fetch(url);
    var data = await res.json();
    if (!data || !data.episodes || !data.episodes.length) throw new Error("No episodes");
    var episodes = [];
    for (var i = 0; i < data.episodes.length; i++) {
      var ep = data.episodes[i];
      episodes.push({ id: ep.id, title: ep.title || ("Episode " + ep.number), number: ep.number, url: ep.url || "" });
    }
    return episodes;
  }
  async findEpisodeServer(episode, server) {
    var serverParam = server === "Vidstreaming SUB" ? "vidstreaming" : "gogocdn";
    var url = this.base + "/anime/gogoanime/watch/" + encodeURIComponent(episode.id) + "?server=" + serverParam;
    var res = await fetch(url);
    var data = await res.json();
    if (!data || !data.sources || !data.sources.length) {
      var fb = serverParam === "gogocdn" ? "vidstreaming" : "gogocdn";
      var res2 = await fetch(this.base + "/anime/gogoanime/watch/" + encodeURIComponent(episode.id) + "?server=" + fb);
      data = await res2.json();
      if (!data || !data.sources || !data.sources.length) throw new Error("No stream found");
    }
    var sources = [];
    for (var i = 0; i < data.sources.length; i++) {
      var src = data.sources[i];
      if (!src.url) continue;
      sources.push({ url: src.url, quality: src.quality || "auto", type: (src.isM3U8 || src.url.indexOf(".m3u8") !== -1) ? "hls" : "mp4" });
    }
    if (!sources.length) throw new Error("No valid sources");
    sources.sort(function(a, b) { return (parseInt(b.quality) || 0) - (parseInt(a.quality) || 0); });
    return { server: server, videoSources: sources };
  }
}
